"use client";
import { useState, useEffect, useRef } from "react";
import { Cpu, ChevronRight, CheckCircle, AlertTriangle, Search, Database, Radio } from "lucide-react";
import { AGENT_INVESTIGATION_STEPS } from "../lib/agent";

const TOOL_ICONS = {
  fetch_events: Database,
  get_zone_context: Search,
  cross_reference_events: Radio,
  fetch_drone_telemetry: Navigation => Radio,
  check_badge_registry: Search,
  assess_weather_context: Radio,
  flag_for_escalation: AlertTriangle,
  draft_briefing_section: CheckCircle,
};

const TOOL_COLORS = {
  fetch_events: "#3b82f6",
  get_zone_context: "#8b5cf6",
  cross_reference_events: "#f59e0b",
  fetch_drone_telemetry: "#3b82f6",
  check_badge_registry: "#ef4444",
  assess_weather_context: "#10b981",
  flag_for_escalation: "#ef4444",
  draft_briefing_section: "#10b981",
};

const PHASE_LABELS = {
  discovery: "Discovery",
  investigation: "Investigation",
  correlation: "Correlation",
  assessment: "Assessment",
  drafting: "Drafting",
};

const PHASE_COLORS = {
  discovery: "#3b82f6",
  investigation: "#8b5cf6",
  correlation: "#f59e0b",
  assessment: "#ef4444",
  drafting: "#10b981",
};

export default function AgentPanel({ steps, running, done, onStart }) {
  const scrollRef = useRef(null);
  const [collapsed, setCollapsed] = useState(false);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [steps]);

  const progress = done ? 100 : Math.round((steps.length / AGENT_INVESTIGATION_STEPS.length) * 100);

  return (
    <div className="section-card">
      {/* Header */}
      <div className="flex items-center gap-3 mb-4">
        <div className="w-8 h-8 rounded-lg flex items-center justify-center"
          style={{ background: "rgba(245,158,11,0.1)", border: "1px solid rgba(245,158,11,0.2)" }}>
          <Cpu size={16} style={{ color: "var(--brand-amber)" }} />
        </div>
        <div className="flex-1">
          <div className="flex items-center gap-2">
            <span className="text-sm font-semibold" style={{ color: "var(--text-primary)" }}>AI Investigation Agent</span>
            {running && <span className="animate-pulse-amber text-xs px-2 py-0.5 rounded-full"
              style={{ background: "rgba(245,158,11,0.1)", color: "var(--brand-amber)", border: "1px solid rgba(245,158,11,0.2)" }}>
              RUNNING
            </span>}
            {done && <span className="text-xs px-2 py-0.5 rounded-full"
              style={{ background: "rgba(16,185,129,0.1)", color: "#6ee7b7", border: "1px solid rgba(16,185,129,0.25)" }}>
              COMPLETE
            </span>}
          </div>
          <div className="text-xs mt-0.5" style={{ color: "var(--text-muted)" }}>
            MCP-style tool-calling · {steps.length}/{AGENT_INVESTIGATION_STEPS.length} steps
          </div>
        </div>
        <button onClick={() => setCollapsed(p => !p)}
          className="text-xs px-2 py-1 rounded transition-colors"
          style={{ color: "var(--text-muted)", background: "var(--surface-2)", border: "1px solid var(--border-subtle)" }}>
          {collapsed ? "Expand" : "Collapse"}
        </button>
      </div>

      {/* Progress bar */}
      <div className="mb-4">
        <div className="flex justify-between text-xs mb-1.5" style={{ color: "var(--text-muted)" }}>
          <span>Investigation Progress</span>
          <span style={{ color: done ? "var(--brand-green)" : "var(--brand-amber)" }}>{progress}%</span>
        </div>
        <div className="h-1.5 rounded-full" style={{ background: "var(--surface-3)" }}>
          <div className="h-full rounded-full transition-all duration-500"
            style={{
              width: `${progress}%`,
              background: done
                ? "linear-gradient(90deg, #10b981, #6ee7b7)"
                : "linear-gradient(90deg, #d97706, #f59e0b)",
            }} />
        </div>
      </div>

      {/* Start prompt */}
      {!running && !done && steps.length === 0 && (
        <div className="rounded-lg p-4 text-center"
          style={{ background: "var(--surface-0)", border: "1px solid var(--border-subtle)" }}>
          <div className="text-2xl mb-2">🛰️</div>
          <p className="text-sm font-medium mb-1" style={{ color: "var(--text-primary)" }}>Ready to investigate</p>
          <p className="text-xs mb-3" style={{ color: "var(--text-muted)" }}>
            The agent will fetch events, check badge registry, cross-reference incidents, assess drone telemetry, and draft the morning briefing.
          </p>
          <button onClick={onStart}
            className="px-4 py-2 rounded-lg text-sm font-semibold transition-all"
            style={{
              background: "rgba(245,158,11,0.15)",
              border: "1px solid rgba(245,158,11,0.35)",
              color: "var(--brand-amber)",
            }}>
            Start Investigation →
          </button>
        </div>
      )}

      {/* Steps stream */}
      {!collapsed && steps.length > 0 && (
        <div ref={scrollRef} className="space-y-2 max-h-64 overflow-y-auto pr-1">
          {steps.map((item, i) => (
            <AgentStep key={item.step.id} item={item} index={i} />
          ))}
          {running && (
            <div className="flex items-center gap-2 py-2">
              <div className="flex gap-1">
                {[0, 1, 2].map(i => (
                  <div key={i} className="w-1.5 h-1.5 rounded-full animate-bounce"
                    style={{ animationDelay: `${i * 150}ms`, background: "var(--brand-amber)" }} />
                ))}
              </div>
              <span className="text-xs" style={{ color: "var(--text-muted)" }}>Thinking…</span>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function AgentStep({ item, index }) {
  const [expanded, setExpanded] = useState(false);
  const { step, result } = item;
  const color = TOOL_COLORS[step.tool] || "#8b949e";
  const phaseColor = PHASE_COLORS[step.phase] || "#8b949e";

  return (
    <div className="animate-slide-in rounded-lg overflow-hidden"
      style={{ background: "var(--surface-0)", border: "1px solid var(--border-subtle)", animationDelay: `${index * 50}ms` }}>
      <div className="flex items-center gap-2 px-3 py-2 cursor-pointer hover:bg-gray-900 transition-colors"
        onClick={() => setExpanded(p => !p)}>
        <div className="w-5 h-5 rounded flex items-center justify-center shrink-0"
          style={{ background: `${color}18`, border: `1px solid ${color}30` }}>
          <span style={{ color, fontSize: 10 }}>⚙</span>
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="text-xs font-mono font-medium" style={{ color }}>{step.tool}</span>
            <span className="text-xs px-1.5 py-0.5 rounded"
              style={{ background: `${phaseColor}12`, color: phaseColor, border: `1px solid ${phaseColor}20`, fontSize: 10 }}>
              {PHASE_LABELS[step.phase]}
            </span>
          </div>
          <div className="text-xs truncate" style={{ color: "var(--text-muted)" }}>{step.label}</div>
        </div>
        <CheckCircle size={13} style={{ color: "var(--brand-green)", shrink: 0 }} />
        <ChevronRight size={12} style={{ color: "var(--text-muted)", transform: expanded ? "rotate(90deg)" : "none", transition: "transform 0.2s" }} />
      </div>

      {expanded && (
        <div className="px-3 pb-3 space-y-2 border-t" style={{ borderColor: "var(--border-subtle)" }}>
          {/* Thinking */}
          <div className="mt-2 px-2 py-2 rounded text-xs italic"
            style={{ background: "rgba(245,158,11,0.04)", border: "1px solid rgba(245,158,11,0.1)", color: "var(--text-muted)" }}>
            💭 {step.thinking}
          </div>
          {/* Tool call */}
          <div>
            <div className="text-xs font-medium mb-1" style={{ color: "var(--text-muted)" }}>Tool Call</div>
            <pre className="text-xs rounded p-2 overflow-x-auto"
              style={{ background: "var(--surface-2)", color: "#93c5fd", fontFamily: "var(--font-mono)" }}>
              {JSON.stringify({ tool: step.tool, params: step.params }, null, 2)}
            </pre>
          </div>
          {/* Result */}
          <div>
            <div className="text-xs font-medium mb-1" style={{ color: "var(--text-muted)" }}>Result</div>
            <pre className="text-xs rounded p-2 overflow-x-auto max-h-40"
              style={{ background: "var(--surface-2)", color: "#6ee7b7", fontFamily: "var(--font-mono)" }}>
              {JSON.stringify(result, null, 2).slice(0, 600)}{JSON.stringify(result, null, 2).length > 600 ? "\n…" : ""}
            </pre>
          </div>
        </div>
      )}
    </div>
  );
}
